const comments={getAntiForgeryToken:function(){const a=document.querySelector('input[name="__RequestVerificationToken"]');return a?a.value:''},getHeaders:function(){return{'RequestVerificationToken':this.getAntiForgeryToken(),'Content-Type':'application/json'}},toggleForm:function(a){const b=document.getElementById('comment-form');const c=document.getElementById('comment-replied-on');if(b.style.display==='none'){b.style.display='block';if(a){c.value=a}else{c.value=''}document.getElementById('comment-text').focus()}else{b.style.display='none';c.value='';document.getElementById('comment-text').value=''}},submit:async function(){const a=document.querySelector('.comments-section');const b=a.dataset.commentedOn;const c=document.getElementById('comment-text').value.trim();const d=document.getElementById('comment-replied-on').value;if(!c){alert('Please enter a comment.');return}try{const e=await fetch('/api/comments/create',{method:'POST',headers:this.getHeaders(),body:JSON.stringify({commentedOn:b,repliedOn:d||null,text:c,attachments:[]})});if(e.ok){const f=await e.json();if(f.success){window.location.reload()}}else if(e.status===403){alert('You are not authorized to comment.')}else{alert('Failed to submit comment.')}}catch(g){alert('Network error: '+g.message)}},reply:function(a){this.toggleForm(a)},deleteComment:async function(a){if(!confirm('Are you sure you want to delete this comment?'))return;try{const b=await fetch('/api/comments/'+a+'/delete',{method:'POST',headers:this.getHeaders()});if(b.ok){window.location.reload()}}catch(c){alert('Network error: '+c.message)}},updateStatus:async function(a,b){try{const c=await fetch('/api/comments/'+a+'/status',{method:'POST',headers:this.getHeaders(),body:JSON.stringify({status:b})});if(c.ok){window.location.reload()}}catch(d){alert('Network error: '+d.message)}},edit:async function(a){const b=prompt('Edit your comment:');if(!b)return;try{const c=await fetch('/api/comments/'+a+'/update',{method:'POST',headers:this.getHeaders(),body:JSON.stringify({text:b})});if(c.ok){window.location.reload()}}catch(d){alert('Network error: '+d.message)}}};
